import { initMercadoPago, CardPayment } from '@mercadopago/sdk-react';
initMercadoPago('TEST-de563cac-2acb-4ec6-b506-9fb302a2848d');
import { Box } from '@mui/material';
import React, { memo } from 'react';

export const getCardToken = async (): Promise<any> => {
    return (window as any)?.cardPaymentBrickController.getFormData()
        .then((cardFormData: any) => {
            return cardFormData
        })
        .catch((error: any) => {
            console.log('error:', error)
            return null;
        });
}

interface MpProps {
    amount: number;
    initialEmail: string;
    initialDocument: string;
}

const MercadoPagoCheckout = memo<MpProps>(({ amount, initialEmail, initialDocument }) => {
    return <Box
        mt={2}
        style={{ fontFamily: "Arial, Helvetica, sans-serif" }}
    >
        <CardPayment
            initialization={{
                amount: amount,
                payer: {
                    email: initialEmail || "",
                    identification: {
                        type: "CPF",
                        number: initialDocument || ""
                    }
                }
            }}
            customization={{
                paymentMethods: {
                    maxInstallments: 6
                },
                visual: {
                    hideFormTitle: true,
                    hidePaymentButton: true,
                    style: {
                        customVariables: {
                            baseColor: "black",
                            formPadding: '0px'
                        }
                    }
                }
            }}
            onSubmit={async (param) => {
                console.log(param);
            }}
        />
    </Box>
});

export default MercadoPagoCheckout;